example.configuration:

{
  "$connector_name": "Example API Key Auth Connector",
  "$connector_label": "Example API Key Authentication",
  "$connector_description": "Example REST API connector using API Key authentication",
  "$hostname": "https://api.example.com",
  "$authentication": "api_key",
  "$tables": {
    "users": {
      "$path": ["/v1/users"],
      "id": "INTEGER,$key",
      "username": "VARCHAR",
      "email": "VARCHAR",
      "created_at": "TIMESTAMP",
      "is_active": "BOOLEAN",
      "profile": "VARCHAR"
    }
  }
}


{
  "$connector_name": "NBP API Connector",
  "$connector_label": "NBP API",
  "$connector_description": "Connector for Polish National Bank (NBP) public REST API providing exchange rates and gold prices",
  "$hostname": "https://api.nbp.pl",
  "$authentication": "none",
  "$tables": {
    "GOLD_PRICES": {
      "$path": ["/api/cenyzlota/last/50"],
      "ROWID": "VARCHAR,$key",
      "data": "DATE",
      "cena": "DECIMAL"
    }
  }
}


{
  "$connector_name": "Example OAuth2 Auth Connector",
  "$connector_label": "Example OAuth2 Authentication",
  "$connector_description": "Example REST API connector using OAuth2 Bearer Token authentication",
  "$hostname": "https://api.example.com",
  "$authentication": "oauth2",
  "$tables": {
    "customers": {
      "$path": ["/v2/customers"],
      "customer_id": "INTEGER,$key",
      "first_name": "VARCHAR",
      "last_name": "VARCHAR",
      "email": "VARCHAR",
      "registration_date": "DATE",
      "total_purchases": "DECIMAL"
    }
  }
}


{
  "$connector_name": "Example Basic Auth Connector",
  "$connector_label": "Example Basic Authentication",
  "$connector_description": "Example REST API connector using Basic (username/password) authentication",
  "$hostname": "https://api.example.com",
  "$authentication": "basic",
  "$tables": {
    "employees": {
      "$path": ["/api/employees"],
      "employee_id": "INTEGER,$key",
      "first_name": "VARCHAR",
      "last_name": "VARCHAR",
      "email": "VARCHAR",
      "department": "VARCHAR",
      "hire_date": "DATE",
      "salary": "DECIMAL",
      "is_manager": "BOOLEAN"
    }
  }
}


{
  "$connector_name": "Product Catalog API",
  "$connector_label": "Product Catalog",
  "$connector_description": "Product catalog with complex nested structures",
  "$hostname": "https://api.example.com",
  "$authentication": "none",
  "$tables": {
    "products": {
      "$path": ["/api/products"],
      "id": "VARCHAR,$key",
      "name": "VARCHAR",
      "price": "DECIMAL",
      "specifications": "VARCHAR",
      "reviews": "VARCHAR",
      "variants": "VARCHAR"
    }
  }
}
